sql:
SELECT project_id, COUNT(*) AS total_parameters
FROM technical_parameters
GROUP BY project_id;

SELECT AVG(bval) AS average_bval
FROM technical_parameters
WHERE project_id = 1;

SELECT parameter_type, unit
FROM technical_parameters
ORDER BY parameter_type ASC;

SELECT project_id AS "Project ID"
FROM projects
ORDER BY project_id;

